  3	import { RESTApi } from '@API/REST.api';
  4	import { DEFAULT_ISSUER, DEFAULT_SERVICE_ACCOUNT, I18nNamespace } from '@config/config';
  5	import { NamespaceManager } from '@config/db';
  6	import { TooltipInfoButton } from '@core/components/HelpTooltip';
  7	import LoadingPage from '@core/components/Loading';
  8	import { createSiteData } from '@core/utils/createCRD';
  9	import useValidatedInput from '@hooks/useValidation';
 10	import { SiteCrdParams } from '@interfaces/CRD_Site';
 11	import { HTTPError } from '@interfaces/REST.interfaces';
 12	import {
 13	  Form,
 14	  FormGroup,
 15	  TextInput,
 16	  ActionGroup,
 17	  Button,
 18	  FormAlert,
 19	  Alert,
 20	  FormSelect,
 21	  FormSelectOption,
 22	  Checkbox,
 23	  Panel,
 24	  PanelMain,
 25	  PanelMainBody,
 26	  Card,
 27	  PageSection,
 28	  PageSectionVariants,
 29	  CardBody,
 30	  ExpandableSection
 31	} from '@patternfly/react-core';
 32	import { useMutation } from '@tanstack/react-query';
 33	import { useTranslation } from 'react-i18next';
 34	
 35	const options = [
 36	  { value: 'route', label: 'route', disabled: false },
 37	  { value: 'loadbalancer', label: 'loadbalancer', disabled: false },
 38	  { value: 'default', label: 'default', disabled: false }
 39	];
 40	
 41	interface SiteFormProps {
 42	  siteName?: string;
 43	  linkAccess?: string;
 44	  serviceAccount?: string;
 45	  defaultIssuer?: string;
 46	  ha?: boolean;
 47	  resourceVersion?: string;
 48	  show?: { linkAccess?: boolean; name?: boolean; ha?: boolean; serviceAccount?: boolean; defaultIssuer?: boolean };
 49	  onCancel: () => void;
 50	}
 51	
 52	const SiteForm: FC<SiteFormProps> = function ({
 53	  siteName,
 54	  linkAccess: initLinkAccess,
 55	  serviceAccount: initServiceAccount,
 56	  defaultIssuer: initDefaultIssuer,
 57	  ha: initHa,
 58	  resourceVersion,
 59	  show = { linkAccess: true, name: true, ha: true, serviceAccount: true, defaultIssuer: true },
 60	  onCancel
 61	}) {
 62	  const [step, setNextStep] = useState(0);
 63	
 64	  const handleReady = () => {
 65	    if (siteName) {
 66	      onCancel?.();
 67	    } else {
 68	      setNextStep(1);
 69	    }
 70	  };
 71	
 72	  const steps = [
 73	    <FormPage
 74	      key={1}
 75	      show={show}
 76	      siteName={siteName}
 77	      initLinkAccess={initLinkAccess}
 78	      initServiceAccount={initServiceAccount}
 79	      initDefaultIssuer={initDefaultIssuer}
 80	      initHa={initHa}
 81	      resourceVersion={resourceVersion}
 82	      onSubmit={handleReady}
 83	      onCancel={onCancel}
 84	    />,
 85	    <WaitSiteCreation key={2} />
 86	  ];
 87	
 88	  return steps[step];
 89	};
