328	  showHa,
329	  showDefaultIssuer,
330	  serviceAccount,
331	  defaultIssuer,
332	  ha,
333	  onChangeServiceAccount,
334	  onDefaultIssuer,
335	  onChangeHa
336	}) {
337	  const { t } = useTranslation(I18nNamespace);
338	
339	  return (
340	    <>
341	      {showServiceAccount && (
342	        <FormGroup
343	          fieldId="service-account-input"
344	          label={t('Service account')}
345	          labelIcon={<TooltipInfoButton content={t('tooltipServiceAccount')} />}
346	          data-testid="service-account-group"
347	        >
348	          <TextInput
349	            data-testid="service-account-input"
350	            aria-label="form service account input"
351	            value={serviceAccount}
352	            placeholder={DEFAULT_SERVICE_ACCOUNT}
353	            onChange={(_, value) => onChangeServiceAccount(value)}
354	          />
355	        </FormGroup>
356	      )}
357	
358	      {showDefaultIssuer && (
359	        <FormGroup
360	          fieldId="defaultIssuer-checkbox"
361	          label={t('Default issuer')}
362	          labelIcon={<TooltipInfoButton content={t('tooltipDefaultIssuer')} />}
363	          className="pf-v5-u-mt-md"
364	          data-testid="default-issuer-group"
365	        >
366	          <TextInput
367	            data-testid="default-issuer-input"
368	            aria-label="form Default issuer input"
369	            value={defaultIssuer}
370	            placeholder={DEFAULT_ISSUER}
371	            onChange={(_, value) => onDefaultIssuer(value)}
372	          />
373	        </FormGroup>
374	      )}
375	
376	      {showHa && (
377	        <FormGroup fieldId="ha-checkbox" className="pf-v5-u-mt-md" data-testid="ha-group">
378	          <Checkbox
379	            data-testid="ha-checkbox"
380	            aria-label="form ha checkbox"
381	            id="ha-checkbox"
382	            label={t('tooltipHighAvailability')}
383	            onChange={() => onChangeHa(!ha)}
384	            isChecked={ha}
385	          />
386	        </FormGroup>
387	      )}
388	    </>
389	  );
390	};

